changeSet.sql:
UPDATE grading_criterion gc
    JOIN (
        SELECT id, ROW_NUMBER() OVER (PARTITION BY exercise_id ORDER BY id) - 1 AS order_index
        FROM grading_criterion
    ) ordered ON gc.id = ordered.id
SET gc.grading_criterion_order = ordered.order_index;

UPDATE grading_instruction gi
    JOIN (
        SELECT id, ROW_NUMBER() OVER (PARTITION BY grading_criterion_id ORDER BY id) - 1 AS order_index
        FROM grading_instruction
    ) ordered ON gi.id = ordered.id
SET gi.grading_instruction_order = ordered.order_index;
